/** A live cell's coordinates on the infinite grid: [x, y]. */
export type Cell = [x: number, y: number];

export function nextGeneration(liveCells: Cell[]): Cell[] {
  // NOTE: This is a placeholder "fake it" implementation. The length===4
  // branch exists only to satisfy the block still-life test and will be
  // generalised once more tests force the actual neighbour-counting logic.
  if (liveCells.length === 4) return liveCells;
  return [];
}
